spec.expr:
avg by (Hostname, namespace, pod) (
  DCGM_FI_DEV_GPU_UTIL{Hostname=~"$hostname"} 
  * on (pod) group_left(namespace) 
  kube_pod_info{namespace=~"$namespace"}
)

(
  avg by (Hostname, namespace) (
    DCGM_FI_DEV_FB_USED{Hostname=~"$hostname"} 
    * on (pod) group_left(namespace) 
    kube_pod_info{namespace=~"$namespace"}
  )
  / 
  avg by (Hostname, namespace) (
    (DCGM_FI_DEV_FB_USED{Hostname=~"$hostname"} + DCGM_FI_DEV_FB_FREE{Hostname=~"$hostname"}) 
    * on (pod) group_left(namespace) 
    kube_pod_info{namespace=~"$namespace"}
  )
) * 100
